parameters.jsonOutput:
={{ (() => {
  const meta = JSON.parse($json.message.content);
  const prev = $('🔗 Merge File + Sheet Data').item.json;

  // Calculate next 3:00 PM EDT (UTC-4) = 19:00 UTC
  // If it's already past 19:00 UTC today, schedule for tomorrow
  const now = new Date();
  let target = new Date(now);
  target.setUTCHours(19, 0, 0, 0); // 3 PM EDT = 19:00 UTC
  if (target <= now) {
    target.setUTCDate(target.getUTCDate() + 1);
  }
  const schedule_epoch = Math.floor(target.getTime() / 1000);
  const schedule_iso = target.toISOString();

  return JSON.stringify({
    file_id: prev.file_id,
    file_name: prev.file_name,
    file_code_name: prev.file_code_name,
    video_url: prev.web_content_link,
    row_number: prev.row_number,
    schedule_epoch: schedule_epoch,
    schedule_iso: schedule_iso,
    yt_title: meta.yt_title,
    yt_description: meta.yt_description,
    yt_tags: meta.yt_tags,
    tiktok_caption: meta.tiktok_caption,
    ig_caption: meta.ig_caption,
    fb_caption: meta.fb_caption,
    hashtags: meta.hashtags,
    caption: meta.tiktok_caption,
    captions: [meta.ig_caption]
  });
})() }}
